#include<bits/stdc++.h>
using namespace std;
long long cnt1[11],cnt2[11],dp[21][2][11];
long long a[21],base[21],f[21];
const long long mod=1e9+7;
void solve(long long x,long long *cnt)
{
    long long tot=0;
    while(x)
    {
        a[++tot]=x%10;
        x/=10;
    }
    for(long long i=tot;i>=1;i--)
    {
        for(long long j=0;j<=9;j++)
        {
            cnt[j]+=f[i-1]*a[i]%mod;
            cnt[j]%=mod;
        }
        for(long long j=0;j<a[i];j++)
        {
            cnt[j]+=base[i-1];
            cnt[j]%=mod;
        }
        long long s=0;
        for(long long j=i-1;j>=1;j--)
        {
            s=s*10+a[j];
        }
        cnt[a[i]]+=s+1;
        cnt[a[i]]%=mod;
        cnt[0]-=base[i-1];
        cnt[0]=(cnt[0]%mod+mod)%mod;
    }
}
int main()
{
    base[0]=1;
    for(long long i=1;i<=18;i++)
    {
        f[i]=f[i-1]*10+base[i-1];
        base[i]=base[i-1]*10;
    }
    int t;
    scanf("%d",&t);
    while(t--)
    {
        memset(dp,0,sizeof(dp));
        memset(cnt1,0,sizeof(cnt1));
        memset(cnt2,0,sizeof(cnt2));
        long long l,r;
        scanf("%lld%lld",&l,&r);
        solve(l-1,cnt2);
        solve(r,cnt1);
        long long ans=0;
        for(long long j=1;j<=9;j++)
        {
            ans+=j*(((cnt1[j]-cnt2[j])%mod+mod)%mod)%mod;
            ans%=mod;
        }
        printf("%lld\n",ans);
    }
    return 0;
}
